};

export const WithErrorMessage: Story = {
  parameters: {
    docs: {
      description: {
        story:
          'Manual **`errorMessage`** (or **`errors`** from `[formField]`). Implements **`FormCheckboxControl`** for Angular signal forms on boolean fields.',
      },
