  render: (args) => ({
    props: args,
    moduleMetadata: storyImports,
    template: `
      <div class="au-story-stage">
        <au-button
          variant="outline"
          [auTooltip]="text"
          [auTooltipPlacement]="placement"
          [auTooltipShowDelay]="showDelay"
